# --- Error Handling Utilities ---

class ErrorCorrelation:
    """Maps internal error IDs to detailed error info, kept server-side only."""

    _store = {}

    @classmethod
    def record(cls, error_id, exception, tb, context_info=None):
        """Record full error details server-side, indexed by correlation ID."""
        cls._store[error_id] = {
            'exception_type': type(exception).__name__,
            'exception_message': str(exception),
            'traceback': tb,
            'context_info': context_info or {},
        }
        logger.error(
            "Error [%s]: %s: %s\nTraceback:\n%s\nContext: %s",
            error_id,
            type(exception).__name__,
            str(exception),
            tb,
            context_info,
        )

    @classmethod
    def get(cls, error_id):
        return cls._store.get(error_id)


def safe_error_response(context, status_code, error_id, user_message):
    """
    Set a safe gRPC error response that does NOT leak internal details.
    
    The error_id allows operators to correlate with server-side logs
    without exposing stack traces, internal state, or implementation
    details to the client.
    """
    # Only provide the correlation ID and a generic message to the client
    safe_detail = f"{user_message} (error_id: {error_id})"
    context.set_code(status_code)
    context.set_details(safe_detail)


def handle_service_error(context, exception, method_name, context_info=None):
    """
    Centralized error handler that:
    - Generates a unique error correlation ID
    - Logs full details (traceback, internal state) server-side
    - Returns only a safe, generic message to the client
    """
    error_id = str(uuid.uuid4())
    tb = traceback.format_exc()

    # Record everything server-side
    full_context = {
        'method': method_name,
        **(context_info or {}),
    }
    ErrorCorrelation.record(error_id, exception, tb, full_context)

    # Determine appropriate status code and generic message
    if isinstance(exception, ValueError):
        safe_error_response(
            context,
            StatusCode.INVALID_ARGUMENT,
            error_id,
            "Invalid input provided. Please check your request parameters.",
        )
    elif isinstance(exception, PermissionError):
        safe_error_response(
            context,
            StatusCode.PERMISSION_DENIED,
            error_id,
            "Permission denied.",
        )
    elif isinstance(exception, FileNotFoundError):
        safe_error_response(
            context,
            StatusCode.NOT_FOUND,
            error_id,
            "The requested resource was not found.",
        )
    elif isinstance(exception, ZeroDivisionError):
        safe_error_response(
            context,
            StatusCode.INVALID_ARGUMENT,
            error_id,
            "Invalid operation: division by zero.",
        )
    elif isinstance(exception, TimeoutError):
        safe_error_response(
            context,
            StatusCode.DEADLINE_EXCEEDED,
            error_id,
            "The operation timed out. Please try again.",
        )
    elif isinstance(exception, NotImplementedError):
        safe_error_response(
            context,
            StatusCode.UNIMPLEMENTED,
            error_id,
            "This operation is not supported.",
        )
    else:
        safe_error_response(
            context,
            StatusCode.INTERNAL,
            error_id,
            "An internal error occurred. Please contact support with the error_id.",
        )

    return error_id


