ALLOWED_OPERATIONS = {'add', 'subtract', 'multiply', 'divide'}


def validate_calculate_request(request):
    """Validate input before processing."""
    if not request.operation:
        raise ValueError("Operation must be specified.")
    if request.operation.lower() not in ALLOWED_OPERATIONS:
        raise ValueError(
            f"Unsupported operation. Allowed: {', '.join(sorted(ALLOWED_OPERATIONS))}"
        )
    if not isinstance(request.operand_a, (int, float)):
        raise ValueError("operand_a must be a number.")
    if not isinstance(request.operand_b, (int, float)):
        raise ValueError("operand_b must be a number.")


def validate_user_id(user_id):
    """Validate user ID format."""
    if not user_id or not isinstance(user_id, str):
        raise ValueError("user_id must be a non-empty string.")
    if len(user_id) > 128:
        raise ValueError("user_id is too long.")


